from enum import Enum
from typing import List, Tuple, Dict

EPSILON = 1e-8


class Algorithm(Enum):
    CMAES = 1,
    MAES = 2,
    IPOP = 3


FUNCTION_OPTIMAL_VALUES: Dict[str, int] = {
    "F10: Composition Function 3 (F24 CEC-2017)": 2500,
    "F1: Shifted and Rotated Bent Cigar Function (F1 CEC-2017)": 100,
    "F2: Shifted and Rotated Schwefel’s Function (F11 CEC-2014)": 1100,
    "F3: Shifted and Rotated Lunacek bi-Rastrigin Function (F7 CEC-2017)": 700,
    "F4: Expanded Rosenbrock’s plus Griewangk’s Function (F15 CEC-2014)": 1900,
    "F17: Hybrid Function 1 (F17 CEC-2014)": 1700,
    "F16: Hybrid Function 2 (F15 CEC-2017)": 1600,
    "F7: Hybrid Function 3 (F21 CEC-2014)": 2100,
    "F8: Composition Function 1 (F21 CEC-2017)": 2200,
    "F9: Composition Function 2 (F23 CEC-2017)": 2400
}


class Function:
    def __init__(self,
                 name: str,
                 raw_scores: List[float]):
        self.name = name
        self.raw_scores = raw_scores

        self.global_min = FUNCTION_OPTIMAL_VALUES.get(name)
        self.local_min = min(raw_scores)
        self.local_avg = sum(raw_scores) / len(raw_scores)
        self.local_max = max(raw_scores)

        self.worst_min = None   # float
        self.rank = None        # int

    def ne(self):
        if (self.local_min - self.global_min) < EPSILON:
            return 0
        else:
            return (self.local_min - self.global_min) / (self.worst_min - self.global_min)


class Packet:
    def __init__(self,
                 algorithm: Algorithm,
                 dimension: int,
                 raw_results: List[Tuple[str, List[float]]]):
        self.algorithm = algorithm
        self.dimension = dimension
        self.raw_results = raw_results

        self.f_results = list[Function]()


def preprocess_score(packets: List[Packet]):
    worst_mins = dict[int, Dict[str, float]]()

    for packet in packets:
        if packet.dimension not in worst_mins.keys():
            worst_mins[packet.dimension] = {name: float('-inf') for name in FUNCTION_OPTIMAL_VALUES.keys()}
        for function in packet.raw_results:
            fn = Function(function[0], function[1])
            packet.f_results.append(fn)
            if fn.local_min > worst_mins[packet.dimension][fn.name]:
                worst_mins[packet.dimension][fn.name] = fn.local_min

    for packet in packets:
        for function in packet.f_results:
            function.worst_min = worst_mins[packet.dimension][function.name]

    for dimension in worst_mins:
        for function_name in FUNCTION_OPTIMAL_VALUES.keys():
            ranks = list[Tuple[Function, float]]()
            for packet in [p for p in packets if p.dimension == dimension]:
                function = [f for f in packet.f_results if f.name == function_name][0]
                ranks.append((function, function.local_avg))

            ranks.sort(key=lambda x: x[1])
            for i in range(len(ranks)):
                if (ranks[i][0].local_min - ranks[i][0].global_min) < EPSILON:
                    ranks[i][0].rank = 1
                else:
                    ranks[i][0].rank = i + 1


def get_score_1(packets: List[Packet]):
    sne = dict[Algorithm, float]()
    s1: dict[Algorithm, float]

    for packet in packets:
        if packet.algorithm not in sne.keys():
            sne[packet.algorithm] = 0

    for algorithm in sne.keys():
        score = 0
        for packet in [p for p in packets if p.algorithm == algorithm]:
            dim_score = 0
            for function in packet.f_results:
                dim_score += function.ne()
            score += 0.5 * dim_score
        sne[algorithm] = score

    sne_min = min(sne.values())
    s1 = {s: (1 - (sne[s] - sne_min)/sne[s]) * 50 for s in sne.keys()}

    return s1


def get_score_2(packets: List[Packet]):
    sr = dict[Algorithm, float]()
    s2: dict[Algorithm, float]

    for packet in packets:
        if packet.algorithm not in sr.keys():
            sr[packet.algorithm] = 0

    for algorithm in sr.keys():
        score = 0
        for packet in [p for p in packets if p.algorithm == algorithm]:
            dim_score = 0
            for function in packet.f_results:
                dim_score += function.rank
            score += 0.5 * dim_score
        sr[algorithm] = score

    sr_min = min(sr.values())
    s2 = {s: (1 - (sr[s] - sr_min) / sr[s]) * 50 for s in sr.keys()}

    return s2


def calculate_score(packets: List[Packet]):
    preprocess_score(packets)
    s1 = get_score_1(packets)
    s2 = get_score_2(packets)

    s = dict[Algorithm, float]()
    for algorithm in s1.keys():
        s[algorithm] = s1[algorithm] + s2[algorithm]

    return s


